187→func parseDiffStats(diff string) diffStatsResult {
188→	var result diffStatsResult
189→	if diff == "" {
190→		return result
191→	}
192→
193→	var current *fileDiffStat
194→	for _, line := range strings.Split(diff, "\n") {
195→		if strings.HasPrefix(line, "diff --git") {
196→			if current != nil {
197→				result.files = append(result.files, *current)
198→			}
199→			parts := strings.Fields(line)
200→			name := ""
201→			if len(parts) >= 4 {
202→				name = strings.TrimPrefix(parts[3], "b/")
203→			}
204→			current = &fileDiffStat{name: name}
205→		} else if current != nil {
206→			if strings.HasPrefix(line, "+") && !strings.HasPrefix(line, "+++") {
207→				current.add++
208→			} else if strings.HasPrefix(line, "-") && !strings.HasPrefix(line, "---") {
209→				current.del++
210→			}
211→		}
212→	}
213→	if current != nil {
214→		result.files = append(result.files, *current)
215→	}
216→
217→	for _, f := range result.files {
218→		result.totalAdd += f.add
219→		result.totalDel += f.del
220→	}
221→
222→	return result
223→}
