237→	padding := width - lipgloss.Width(headerLine) - lipgloss.Width(totalStat) - 4
238→	if padding < 2 {
239→		padding = 2
240→	}
241→	sb.WriteString(sectionHeaderStyle.Render(headerLine) + strings.Repeat(" ", padding) + totalStat)
242→	sb.WriteString("\n")
243→
244→	nameWidth := width - 24
245→	if nameWidth < 20 {
246→		nameWidth = 20
247→	}
248→
249→	for _, f := range stats.files {
250→		name := f.name
251→		if len(name) > nameWidth {
252→			name = "…" + name[len(name)-nameWidth+1:]
253→		}
254→
255→		fileStat := addStyle.Render(fmt.Sprintf("+%d", f.add)) + " " +
256→			delStyle.Render(fmt.Sprintf("-%d", f.del))
257→		pad := width - len(name) - lipgloss.Width(fileStat) - 8
258→		if pad < 2 {
259→			pad = 2
260→		}
261→		sb.WriteString("    " + name + strings.Repeat(" ", pad) + fileStat + "\n")
262→	}
263→
264→	return sb.String()
265→}
