270→	}
271→
272→	contentWidth := width - 6
273→	if contentWidth < 30 {
274→		contentWidth = 30
275→	}
276→
277→	var sb strings.Builder
278→	sb.WriteString(sectionHeaderStyle.Render("  Plan"))
279→	sb.WriteString("\n\n")
280→
281→	rendered := renderMarkdown(plan, contentWidth)
282→	for _, line := range strings.Split(rendered, "\n") {
283→		sb.WriteString("  " + line + "\n")
284→	}
285→
286→	return sb.String()
287→}
288→
289→func wordWrap(text string, width int) string {
290→	if width <= 0 {
291→		return text
292→	}
293→	var result strings.Builder
294→	for _, line := range strings.Split(text, "\n") {
295→		if len(line) <= width {
296→			result.WriteString(line + "\n")
297→			continue
298→		}
299→		remaining := line
300→		for len(remaining) > width {
301→			breakAt := width
302→			if idx := strings.LastIndex(remaining[:width], " "); idx > 0 {
303→				breakAt = idx
304→			}
305→			result.WriteString(remaining[:breakAt] + "\n")
306→			remaining = strings.TrimLeft(remaining[breakAt:], " ")
307→		}
308→		if remaining != "" {
309→			result.WriteString(remaining + "\n")
310→		}
311→	}
312→	return strings.TrimRight(result.String(), "\n")
313→}
